description:
Wrong result when compare 'null' with subquery result.
How to repeat:
testcase like below:

create dabase test;

create table t1(c1 int, c2 int);

insert into t1 values(10, 10);

select ('a',null) <=> (select 'a',c2 from t1 where c2 = 0);
('a',null) <=> (select 'a',c2 from t1 where c2 = 0)
0

truncate t1;

select ('a',null) <=> (select 'a',c2 from t1 where c2 = 0);
('a',null) <=> (select 'a',c2 from t1 where c2 = 0)
1
